# Write your MySQL query statement below
select st.student_id as student_id,st.student_name as student_name,sb.subject_name as subject_name ,count(e.subject_name) as attended_exams from Students as st cross join Subjects as sb left join Examinations as e on st.student_id = e.student_id and sb.subject_name = e.subject_name GROUP BY st.student_id, st.student_name, sb.subject_name ORDER BY st.student_id, sb.subject_name;